def solve(source, destination):
    if not isinstance(source, (str, list)) or not isinstance(destination, str):
        raise ValueError("Invalid input types: source must be a string or list, destination must be a string.")

    if isinstance(source, str):
        source_data = [source]
    else:
        source_data = source

    # Simulate data extraction
    extracted_data = []
    for item in source_data:
        if isinstance(item, str) and item.strip():
            extracted_data.append(item.strip())

    # Simulate data transformation (for simplicity, just converting to uppercase)
    transformed_data = [data.upper() for data in extracted_data]

    # Simulate data loading
    try:
        with open(destination, 'w') as dest_file:
            for data in transformed_data:
                dest_file.write(data + '\n')
    except Exception as e:
        raise IOError(f"Failed to write to destination: {e}")

    return len(transformed_data)
